// DaxlinePro TTF fonts voor jsPDF – automatisch gegenereerd
// Laad dit bestand NA jsPDF maar VOOR generateUrenstaat()
(function() {
    var fonts = {};
    fonts["DaxlinePro-Regular"] = "";
    fonts["DaxlinePro-Bold"] = "";

    // Wacht tot jsPDF geladen is, registreer dan de fonts
    function tryRegister() {
        if (!window.jspdf) { setTimeout(tryRegister, 200); return; }
        var jsPDF = window.jspdf.jsPDF;
        var callAddFont = function() {
            this.addFileToVFS('DaxlinePro-Regular.ttf', fonts['DaxlinePro-Regular']);
            this.addFont('DaxlinePro-Regular.ttf', 'DaxlinePro', 'normal');
            this.addFileToVFS('DaxlinePro-Bold.ttf', fonts['DaxlinePro-Bold']);
            this.addFont('DaxlinePro-Bold.ttf', 'DaxlinePro', 'bold');
        };
        jsPDF.API.events.push(['addFonts', callAddFont]);
        console.log('DaxlinePro TTF fonts geregistreerd bij jsPDF');
    }
    tryRegister();
})();
